#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int a,b,c,d;    d=0;    cin >>a>>b>>c;    if(c%2 != 0 ){        d=c/2+1;        if(a+d > b+c/2){            cout <<"First" << "\n";        }        else{            cout <<"Second" << "\n";        }    }    else if(c%2 ==0 ){        if(a>b){            cout <<"First" << "\n";        }        else{           cout <<"Second" << "\n";         }            }             }      // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}